import{c as a,Q as n,j as i,m as t}from"./chunks/framework.Bhbi9jCp.js";const k=JSON.parse('{"title":"进程的内存布局","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/07-进程的内存布局.md","filePath":"osLearning/07-进程的内存布局.md","lastUpdated":1781095972000}'),e={name:"osLearning/07-进程的内存布局.md"};function p(l,s,o,h,d,r){return n(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="进程的内存布局" tabindex="-1">进程的内存布局 <a class="header-anchor" href="#进程的内存布局" aria-label="Permalink to &quot;进程的内存布局&quot;">​</a></h1><p>运维拿着 <code>top</code> 来质问:&quot;你这 Java 服务 -Xmx 才 4G,凭什么 RES 飙到 6G?&quot;——如果你答不上来,说明你脑子里没有那张图:<strong>每个 Linux 进程的虚拟地址空间是一张固定格式的地图</strong>,代码、数据、堆、栈、共享库各占一段,各有各的脾气。堆只是其中一段,-Xmx 只管堆;栈溢出(stack overflow)这个词为什么叫&quot;溢出&quot;、<code>free</code> 了内存为什么不还给系统、字符串字面量为什么改一下就 segfault——答案全画在这张图上。这一篇把它逐段剖开。</p><blockquote><p>一句话先记住:<strong>进程地址空间 = 代码段 + 数据段 + 堆(向上长)+ mmap 区(共享库和大块内存)+ 栈(向下长)+ 内核空间</strong>,堆和栈中间隔着几 TB 的空洞。<strong>-Xmx 只限制 Java 堆,而进程真实内存还有线程栈、Metaspace、Direct Buffer、JIT 代码、Native 库</strong>——这就是容器里 Java 被 OOMKilled 时大家一脸懵的原因。</p></blockquote><hr><h2 id="一、先看全图" tabindex="-1">一、先看全图 <a class="header-anchor" href="#一、先看全图" aria-label="Permalink to &quot;一、先看全图&quot;">​</a></h2><p>x86_64 上一个典型进程的地址空间(上一篇讲过,用户空间和内核空间各 128TB,中间是硬件造成的非规范地址空洞):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0xFFFF_FFFF_FFFF_FFFF ┌──────────────────────┐</span></span>
<span class="line"><span>                      │  内核空间(128TB)      │ 所有进程共享同一份</span></span>
<span class="line"><span>0xFFFF_8000_0000_0000 ├──────────────────────┤</span></span>
<span class="line"><span>                      │  非规范地址空洞        │ 硬件只用 48 位地址</span></span>
<span class="line"><span>0x0000_7FFF_FFFF_FFFF ├──────────────────────┤</span></span>
<span class="line"><span>                      │  栈 Stack    ↓ 向下长 │ 局部变量 / 函数调用</span></span>
<span class="line"><span>                      ├──────────────────────┤</span></span>
<span class="line"><span>                      │  mmap 区域   ↓        │ 共享库 / 大块 malloc / 线程栈</span></span>
<span class="line"><span>                      ├── (几 TB 的空洞) ─────┤</span></span>
<span class="line"><span>                      │  堆 Heap     ↑ 向上长 │ malloc / new</span></span>
<span class="line"><span>                      ├──────────────────────┤</span></span>
<span class="line"><span>                      │  .bss   未初始化全局   │</span></span>
<span class="line"><span>                      │  .data  已初始化全局   │</span></span>
<span class="line"><span>                      │  .rodata 只读数据      │</span></span>
<span class="line"><span>                      │  .text  代码          │</span></span>
<span class="line"><span>0x0000_0000_0040_0000 ├──────────────────────┤</span></span>
<span class="line"><span>                      │  0 附近故意不映射      │ 让空指针解引用必死</span></span>
<span class="line"><span>0x0000_0000_0000_0000 └──────────────────────┘</span></span></code></pre></div><p>最底下那段&quot;故意不映射&quot;很妙:<strong>NULL 解引用之所以稳定地 segfault 而不是悄悄读到垃圾,是因为内核刻意把低地址留空</strong>——这是用地址空间换 debug 体验。</p><p>下面从低往高,一段一段讲。</p><hr><h2 id="二、代码段-text-只读、可执行、大家共享" tabindex="-1">二、代码段(.text):只读、可执行、大家共享 <a class="header-anchor" href="#二、代码段-text-只读、可执行、大家共享" aria-label="Permalink to &quot;二、代码段(.text):只读、可执行、大家共享&quot;">​</a></h2><p>存机器码的地方。权限是 <strong>R-X(只读 + 可执行)</strong>——只读是为了防止程序意外(或恶意)改写自己的代码:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">char</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">char</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)main;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        // segfault,.text 不许写</span></span></code></pre></div><p>两个工程意义上的好处:</p><ul><li><strong>同一个二进制跑 100 个进程,.text 只占一份物理内存</strong>(只读所以能安全共享)</li><li>现代默认编译成 PIE(位置无关),配合 ASLR 每次加载地址随机化,防攻击;老式 non-PIE 固定从 <code>0x400000</code> 开始</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">size</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /bin/ls</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#    text    data    bss     dec      hex   filename</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">#  120741    4520    788   126049   1ec61   /bin/ls</span></span></code></pre></div><hr><h2 id="三、数据段三兄弟-data-bss-rodata" tabindex="-1">三、数据段三兄弟:.data / .bss / .rodata <a class="header-anchor" href="#三、数据段三兄弟-data-bss-rodata" aria-label="Permalink to &quot;三、数据段三兄弟:.data / .bss / .rodata&quot;">​</a></h2><p>全局变量和静态变量住在这里,但按&quot;有没有初值、能不能改&quot;分了三个小区:</p><table tabindex="0"><thead><tr><th>段</th><th>住户</th><th>权限</th><th>占不占 ELF 文件体积</th></tr></thead><tbody><tr><td><code>.data</code></td><td><code>int g = 100;</code> 有初值的全局/静态</td><td>可读写</td><td>占(初值得存着)</td></tr><tr><td><code>.bss</code></td><td><code>int g_arr[1000000];</code> 零初值的</td><td>可读写</td><td><strong>不占</strong>(文件里只记&quot;我要 4MB 全零&quot;)</td></tr><tr><td><code>.rodata</code></td><td>字符串字面量、<code>const</code> 全局</td><td><strong>只读</strong></td><td>占</td></tr></tbody></table><p><code>.bss</code> 的设计很省:<strong><code>int arr[100000000]</code> 这种全局大数组只让二进制大几个字节,运行时却占 400MB</strong>——内核启动时给它映射共享的零页(COW,写到哪页才真分哪页,和上一篇讲的缺页机制完美衔接)。</p><p><code>.rodata</code> 则是一个新手必踩的坑的来源:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">char</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">p </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hello&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">p</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;H&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        // segfault!&quot;hello&quot; 在 .rodata,只读</span></span></code></pre></div><p><strong>字符串字面量是只读的</strong>。想改就用 <code>char p[] = &quot;hello&quot;;</code>(数组形式会把内容拷到栈或 .data)。</p><hr><h2 id="四、堆-heap-malloc-的地盘-只涨不缩" tabindex="-1">四、堆(Heap):malloc 的地盘,只涨不缩 <a class="header-anchor" href="#四、堆-heap-malloc-的地盘-只涨不缩" aria-label="Permalink to &quot;四、堆(Heap):malloc 的地盘,只涨不缩&quot;">​</a></h2><p><code>malloc</code> / <code>new</code> 的内存来自这里。堆有一个叫 <strong>brk</strong> 的指针标记堆顶,扩堆就是用 <code>brk()</code> 系统调用把它往上挪:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/maps</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> heap</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 555a3d76d000-555a3d791000 rw-p ... [heap]</span></span></code></pre></div><p>但 glibc 的 malloc 并不是所有请求都走堆——它按大小分流:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>小对象(&lt; 128KB,M_MMAP_THRESHOLD):从堆里切一块(brk 扩堆)</span></span>
<span class="line"><span>大对象(≥ 128KB):           直接 mmap 一段独立的匿名内存</span></span></code></pre></div><p>为什么这么分?<strong>小对象分配释放极其频繁,用 brk 池化避免反复 syscall;大对象生命周期长,用 mmap 的好处是 free 时 munmap 直接还给内核</strong>。</p><p>这里埋着本系列最重要的认知之一:<strong>free 不会把堆内存还给操作系统</strong>。glibc 只是把它放回自己的空闲池等下次复用,brk 指针不会缩。所以<strong>长期运行的进程&quot;内存只涨不跌&quot;是常态,不一定是泄漏</strong>——分清&quot;碎片 / 池子&quot;和&quot;真泄漏&quot;是 08 篇的主题。</p><p>观测工具:<code>pmap -x &lt;pid&gt;</code> 看 [heap] 段大小,代码里可以调 <code>malloc_stats()</code> / <code>mallinfo2()</code> 看 glibc 内部账目。</p><hr><h2 id="五、栈-stack-向下生长-有限额-会溢出" tabindex="-1">五、栈(Stack):向下生长,有限额,会溢出 <a class="header-anchor" href="#五、栈-stack-向下生长-有限额-会溢出" aria-label="Permalink to &quot;五、栈(Stack):向下生长,有限额,会溢出&quot;">​</a></h2><p>栈管两件事:函数调用链和局部变量。三个关键性格:</p><ul><li><strong>向下生长</strong>(从高地址往低地址)</li><li><strong>每个线程一条独立的栈</strong></li><li><strong>有限额</strong>,默认 8MB:</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">ulimit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 8192(KB)= 8MB</span></span></code></pre></div><p>每次函数调用压入一个<strong>栈帧(stack frame)</strong>,<code>rsp</code> 寄存器指着栈顶:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>高地址</span></span>
<span class="line"><span>┌──────────────┐ ← main 的栈帧</span></span>
<span class="line"><span>│ 局部变量      │</span></span>
<span class="line"><span>│ 返回地址      │</span></span>
<span class="line"><span>├──────────────┤ ← 被调函数的栈帧</span></span>
<span class="line"><span>│ 参数 / 局部变量│</span></span>
<span class="line"><span>│ 返回地址      │</span></span>
<span class="line"><span>└──────────────┘ ← rsp(继续向下)</span></span>
<span class="line"><span>低地址</span></span></code></pre></div><h3 id="栈的-自动扩展-和溢出" tabindex="-1">栈的&quot;自动扩展&quot;和溢出 <a class="header-anchor" href="#栈的-自动扩展-和溢出" aria-label="Permalink to &quot;栈的&quot;自动扩展&quot;和溢出&quot;">​</a></h3><p>栈区一开始只映射几页,不是一上来就给 8MB:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>访问超出当前栈底的地址 → 缺页中断</span></span>
<span class="line"><span>→ 内核一看:这地址紧挨着栈,是正常生长 → 默默分新页</span></span>
<span class="line"><span>→ 长到 ulimit -s 上限还想长 → 这次真的 segfault</span></span></code></pre></div><p>这就是 <strong>stack overflow</strong> 这个词的字面来源——栈&quot;溢&quot;出了它的限额:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> recurse</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">() {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    int</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;"> big</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // 每层 400KB</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    recurse</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         // 没有出口</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                      // 20 层就撞 8MB 上限,segfault</span></span></code></pre></div><p>两种最常见的爆法:<strong>无限递归</strong>,和<strong>在栈上开大数组</strong>(<code>char buf[10*1024*1024]</code> 一行就爆,大缓冲区请放堆上)。</p><h3 id="guard-page-溢出时为什么是干净地死" tabindex="-1">guard page:溢出时为什么是干净地死 <a class="header-anchor" href="#guard-page-溢出时为什么是干净地死" aria-label="Permalink to &quot;guard page:溢出时为什么是干净地死&quot;">​</a></h3><p>每条线程栈的底部都有一段<strong>哨兵页(guard page)</strong>——故意不映射的虚拟页。栈长过头时会先撞上它,<strong>立刻 segfault,而不是悄悄写穿到隔壁的映射(别的线程栈、共享库数据)</strong>。悄悄写穿才是真正的安全灾难——guard page 让程序&quot;死得明白&quot;。</p><h3 id="多线程的栈" tabindex="-1">多线程的栈 <a class="header-anchor" href="#多线程的栈" aria-label="Permalink to &quot;多线程的栈&quot;">​</a></h3><p>主线程的栈在地址空间顶部,<strong>其他线程的栈是 pthread 用 mmap 在 mmap 区分配的</strong>,默认每条 8MB。算笔账:<strong>1000 个线程 = 8GB 虚拟内存</strong>(物理上因为按需调页通常没那么多)。32 位系统总共才 4GB 地址空间,根本跑不动一万个线程——这是&quot;线程不能无限开&quot;的地址空间维度的原因。</p><hr><h2 id="六、mmap-区-共享库和大块内存的杂居地" tabindex="-1">六、mmap 区:共享库和大块内存的杂居地 <a class="header-anchor" href="#六、mmap-区-共享库和大块内存的杂居地" aria-label="Permalink to &quot;六、mmap 区:共享库和大块内存的杂居地&quot;">​</a></h2><p>堆和栈之间那片巨大的区域归 mmap 管:共享库、大块 malloc、线程栈、文件映射都在这。看一眼共享库的映射:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">$$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/maps</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;\\.so&#39;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 7f4a... r--p ... libc.so.6     ← .rodata</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 7f4a... r-xp ... libc.so.6     ← .text(只读可执行)</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 7f4a... r--p ... libc.so.6</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 7f4a... rw-p ... libc.so.6     ← .data/.bss(私有,COW)</span></span></code></pre></div><p><strong>每个 .so 通常映射 4-5 段</strong>(.text / .rodata / .data / .bss / GOT 等)。重点还是那条:N 个进程都加载 libc,<strong>只读的 .text 段物理内存只占一份</strong>——这是动态链接库省内存的根本机制,也是 RSS 重复计算、要看 PSS 的原因(06 篇讲过)。</p><p>地图顶部还有几个内核放的小东西:<code>[vdso]</code> / <code>[vvar]</code> 是内核映射进每个进程的&quot;快速系统调用页&quot;(<code>gettimeofday</code> 这类高频调用不用真陷入内核)。再往上就是内核空间——用户态碰一下就 segfault,Meltdown 之后 KPTI 还把它在用户态页表里基本清空了,代价是 syscall 慢 5-30%(06 篇讲过)。</p><hr><h2 id="七、名场面-java-进程的真实内存" tabindex="-1">七、名场面:Java 进程的真实内存 <a class="header-anchor" href="#七、名场面-java-进程的真实内存" aria-label="Permalink to &quot;七、名场面:Java 进程的真实内存&quot;">​</a></h2><p>现在可以回答开头运维的质问了。<code>-Xmx 4g</code> 的 Java 进程 RES 6GB,<strong>因为 -Xmx 只管那一段 mmap 出来的 Java 堆,而进程地图上还有一堆别的住户</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>JVM 进程的内存构成:</span></span>
<span class="line"><span>┌────────────────────────────┐</span></span>
<span class="line"><span>│ Java 堆(-Xmx 管的就这个)   │ ← 4GB</span></span>
<span class="line"><span>├────────────────────────────┤</span></span>
<span class="line"><span>│ Metaspace(类元数据)        │ ← 默认无上限!</span></span>
<span class="line"><span>│ Code Cache(JIT 编译产物)   │ ← 几百 MB</span></span>
<span class="line"><span>│ Direct Buffer(NIO 堆外)    │ ← Netty 大户,最容易爆</span></span>
<span class="line"><span>│ 线程栈(默认 1MB × 线程数)   │ ← 1000 线程 = 1GB</span></span>
<span class="line"><span>│ JNI / Native 库内存         │</span></span>
<span class="line"><span>│ GC 元数据(card table 等)   │</span></span>
<span class="line"><span>│ 共享库(.so)                │</span></span>
<span class="line"><span>└────────────────────────────┘</span></span></code></pre></div><p>总和到 -Xmx 的 1.5-3 倍很正常。容器里这就是命案现场:<strong>limit 设成 -Xmx 一样大 → 非堆部分一长 → cgroup OOMKilled → 管理员看着&quot;堆明明没满&quot;一脸懵</strong>。</p><p>对策是给每一块都上限,并给非堆留余量:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-Xmx4g</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-XX:MaxMetaspaceSize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=256m</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-XX:ReservedCodeCacheSize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=256m</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-XX:MaxDirectMemorySize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=1g</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-Xss256k</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                          # 线程多的服务调小单栈</span></span></code></pre></div><p>容器里更推荐 <code>-XX:MaxRAMPercentage=70.0</code>——让 JVM 按容器内存自适应,<strong>总和给非堆留 30%</strong>。(老版 JVM 还看不到 cgroup 限制,会按宿主机内存算堆,Java 10+ 的 <code>UseContainerSupport</code> 修了这个,详见 09 篇。)</p><hr><h2 id="八、排查工具箱" tabindex="-1">八、排查工具箱 <a class="header-anchor" href="#八、排查工具箱" aria-label="Permalink to &quot;八、排查工具箱&quot;">​</a></h2><table tabindex="0"><thead><tr><th>工具</th><th>看什么</th></tr></thead><tbody><tr><td><code>pmap -x &lt;pid&gt;</code></td><td>每段映射的大小 / RSS / Dirty,最直观的&quot;哪段占多少&quot;</td></tr><tr><td><code>cat /proc/&lt;pid&gt;/smaps</code></td><td>每段的 PSS / Swap / Anonymous 等明细</td></tr><tr><td><code>ps -o pid,vsz,rss,cmd</code></td><td>VSZ(虚拟总量)和 RSS(物理占用)速查</td></tr><tr><td><code>jcmd &lt;pid&gt; VM.native_memory summary</code></td><td>Java 各内存区明细(启动需加 <code>-XX:NativeMemoryTracking=detail</code>)</td></tr></tbody></table><p>再加两个相关机制:</p><p><strong>OOM Killer 选谁杀</strong>:<code>cat /proc/&lt;pid&gt;/oom_score</code>,分数 ≈ RSS 占系统内存比例 + <code>oom_score_adj</code>(-1000 永不杀 ~ 1000 优先杀)。K8s 里这个值由 Pod QoS 决定——<strong>BestEffort / Burstable 优先被杀,Guaranteed 最稳</strong>。</p><p><strong>ASan(AddressSanitizer)</strong>:查内存 bug 的神器,<code>gcc -fsanitize=address -g</code> 重编译后,栈溢出、堆越界、use-after-free、double free、泄漏全能抓现行。代价是慢 2-3 倍、内存翻 2-3 倍——<strong>测试环境必开,生产必关</strong>。</p><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><ol><li><strong>改字符串字面量</strong>——<code>char *p = &quot;x&quot;; p[0] = &#39;y&#39;;</code> 必 segfault,字面量在只读的 .rodata</li><li><strong>以为 free 把内存还给系统</strong>——glibc 只放回自己的池子,RSS 不降是常态,不等于泄漏</li><li><strong>线程随便开</strong>——每条默认 8MB 栈(JVM 默认 1MB),千级线程虚拟内存就是 GB 级</li><li><strong>递归不设出口 / 栈上开大数组</strong>——8MB 限额一撞就是 stack overflow,大缓冲区放堆上</li><li><strong>把 -Xmx 当 Java 进程总内存</strong>——真实占用是它的 1.5-3 倍,Metaspace / Direct Buffer / 线程栈都在堆外</li><li><strong>容器 limit 设得和 -Xmx 一样大</strong>——非堆没活路,必被 OOMKilled;用 MaxRAMPercentage=70 留余量</li><li><strong>堆外(Native)泄漏没人查</strong>——Java 堆 dump 干干净净,但 JNI / Direct Buffer 在悄悄漏,要靠 NativeMemoryTracking</li><li><strong>不调 oom_score_adj</strong>——OOM Killer 专杀内存大户,而内存最大的往往是你最关键的服务</li><li><strong>看 RSS 不看 PSS</strong>——共享库被每个进程重复计算</li><li><strong>mmap 大文件用完不 munmap</strong>——虚拟地址空间也是会耗尽的资源</li><li><strong>生产环境开 ASan</strong>——慢 2-3 倍,它是测试工具不是监控工具</li><li><strong>以为调试要关 ASLR</strong>——现代调试器自动处理地址随机化,不用关</li></ol><hr><p>下一篇:<code>08-内存分配.md</code>,钻进堆的内部——<code>malloc(8)</code> 这一行背后 glibc 干了什么(arena / chunk / bins)、为什么多线程程序换个 jemalloc 性能能涨 30%、碎片化怎么把 6GB 的 RSS 里塞出 4GB 的&quot;空气&quot;,以及 Java / Go 为什么干脆不用 malloc。</p>`,75)])])}const g=a(e,[["render",p]]);export{k as __pageData,g as default};
